Question:
CREATE TABLE IF NOT EXISTS bookbrainz.creator_import (
	import_id INT PRIMARY KEY,
	data_id INT
);
ALTER TABLE bookbrainz.creator_import ADD FOREIGN KEY (data_id) REFERENCES bookbrainz.creator_data (id);

Answer:
CREATE TABLE IF NOT EXISTS bookbrainz.creator_import (
	import_id INT PRIMARY KEY,
	data_id INT NOT NULL
);
ALTER TABLE bookbrainz.creator_import ADD FOREIGN KEY (data_id) REFERENCES bookbrainz.creator_data (id);
